nasal.script:
# Some F-16 variants don't expose f16.autostart(); keep tutorial compatible.
if (f16 != nil and contains(f16, "autostart"))
	f16.autostart();


# intialization script
setprop("/controls/gear/gear-down",0);        # remove gear				
setprop("/controls/gear/brake-parking",0);	  # remove parking brake
setprop("/sim/rendering/redout/enabled", 0);
setprop("/sim/rendering/redout/internal/redout", 0);

var apply_intro_cruise_power = func() {
	setprop("/controls/engines/throttle-all", 0.85);
	setprop("/controls/engines/engine[0]/throttle", 0.85);
};
# Tutorial reposition spawns near 350 kt with idle power; re-apply cruise throttle.
settimer(apply_intro_cruise_power, 5.5);
settimer(apply_intro_cruise_power, 12.0);


	# ...
	# update balloon gate position if aircraft passed it 
	# ...

	# sivaks: on starting scenario show dialog to get pilot data
	# fgcommand("dialog-show", props.Node.new({"dialog-name": "sivaks_pilot_info_dlg"}));

	print("SIVAKS_BULLSEYE_SCRIPT v2026-05-13_single-target-purge-ahead loaded");

	# Edge overlay (optional). Never reference bare SivaksTargetEdge — undefined symbol aborts this script.
	var sivaksLoadTargetEdgeNasal = func() {
		if (contains(globals, "SivaksTargetEdge"))
			return 1;
		var path = finddata("Aircraft/f16/Nasal/sivaks_target_edge_indicator.nas");
		if (path == nil) {
			print("SivaksTargetEdge: nasal file not found (overlay skipped)");
			return 0;
		}
		var code = io.readfile(path);
		if (code == nil or size(code) < 1)
			return 0;
		var compiled = compile(code, path);
		if (compiled == nil)
			return 0;
		compiled();
		return contains(globals, "SivaksTargetEdge");
	};

	var sivaksStartTargetEdge = func() {
		if (!sivaksLoadTargetEdgeNasal())
			return;
		# Wait for the main view / canvas desktop to be ready.
		settimer(func {
			if (!contains(globals, "SivaksTargetEdge"))
				return;
			var edge = globals.SivaksTargetEdge;
			if (edge != nil and contains(edge, "init"))
				edge.init();
		}, 2.0);
	};

	var sivaksStopTargetEdge = func() {
		if (!contains(globals, "SivaksTargetEdge"))
			return;
		var edge = globals.SivaksTargetEdge;
		if (edge != nil and contains(edge, "shutdown"))
			edge.shutdown();
	};

	var active_target_id = 0;
	var last_pass_scored_id = -1;
	# Score a pass only after the aircraft was south of the balloon, then crossed north of it.
	setprop("/sim/rendering/redout/enabled", 0);
	setprop("/sim/rendering/redout/internal/redout", 0);

	var apply_cruise_power = func() {
		setprop("/controls/engines/throttle-all", 0.85);
		setprop("/controls/engines/engine[0]/throttle", 0.85);
	};
	# Tutorial reposition spawns near 350 kt with idle power; re-apply cruise throttle.
	apply_cruise_power();
	settimer(apply_cruise_power, 2.0);
	settimer(apply_cruise_power, 8.0);

	# STEP 1: GLOBAL VARIABLES AND FUNCTIONS
	# Use a single balloon model so visuals and behavior are consistent.
	# This is your CorrActions static balloon (bullseye skin).
	var BMODEL = "AI/Aircraft/balloon/ca_sivaks_balloon.xml";
	# Number of balloons before updating difficulty level.
	var BALLOON_per_level = 1;

	# Total balloons required to finish the game
	var MAX_BALLOONS = 8;

	# How many balloons exist simultaneously (the script will move them forward as you pass).
 	var balloon_count = 1;
	var balloonsArray = [];
	setsize(balloonsArray, balloon_count);
	var bullseyeArray = [];
	setsize(bullseyeArray, balloon_count);
	var aimDotArray = [];
	setsize(aimDotArray, balloon_count);
	var bullseyeCallsigns = [];
	setsize(bullseyeCallsigns, balloon_count);
	var bullseyeSerial = 0;
	var bullseyePending = {};
	var bullseyeListenerInstalled = 0;

	setprop("/algorithm/game/balloons-count", 0);
	setprop("/algorithm/game/balloon-scoring-closest-ft", 0);
	setprop("/algorithm/game/balloon-hit", 0);

	var last_balloon_lat = 0;
	var last_balloon_lon = 0;
	var last_balloon_alt = 0;

	var last_balloon_geo_coord = geo.Coord.new();

	# Make the (one-sided) bullseye face the pilot.
	# We compute the course from balloon -> aircraft and use it as the sign's heading.
	var BULLSEYE_HEADING_FLIP_DEG = 0;
	var facePilotHeading = func(lat, lon) {
		var b = geo.Coord.new().set_latlon(lat, lon);
		var ac = geo.aircraft_position();
		return geo.normdeg(b.course_to(ac) + BULLSEYE_HEADING_FLIP_DEG);
	};

	var publishBalloonFacing = func(lat, lon) {
		var face_hdg = facePilotHeading(lat, lon);
		setprop("/algorithm/game/balloon-face-heading-deg", face_hdg);
		return face_hdg;
	};

	var signPositionTowardPilot = func(lat, lon, elevation_ft) {
		var b = geo.Coord.new().set_latlon(lat, lon);
		var ac = geo.aircraft_position();
		var toward = b.course_to(ac);
		b.apply_course_distance(toward, 25);
		return {
			"lat": b.lat(),
			"lon": b.lon(),
			"alt": elevation_ft + BSIGN_ALT_OFFSET_FT
		};
	};

	# Place the next target ahead of the aircraft (northbound tutorial), never behind.
	var computeNextBalloonPosition = func(hardness_level) {
		var ac = geo.aircraft_position();
		var ahead_ft =
			BALLOON_AHEAD_BASE_FT +
			(hardness_level * BALLOON_AHEAD_PER_LEVEL_FT);

		# Always step north first (heading 0), then offset longitude only.
		var spawn_pos = geo.Coord.new().set_latlon(ac.lat(), ac.lon());
		spawn_pos.apply_course_distance(0, ahead_ft);

		var min_ahead_lat = spawn_pos.lat();
		if (min_ahead_lat <= ac.lat())
		{
			spawn_pos = geo.Coord.new().set_latlon(ac.lat(), ac.lon());
			spawn_pos.apply_course_distance(0, ahead_ft);
			min_ahead_lat = spawn_pos.lat();
		}

		var lon_spread =
			0.003 + (hardness_level * 0.00025);
		var spawn_lon = ac.lon() + (rand() - 0.5) * lon_spread * 2;
		var lateral_deg = (spawn_lon - ac.lon()) * 10000;

		var balloon_alt_rand =
			(500 + (hardness_level * 350)) * (rand() - 0.5);
		var new_alt = 2000 + balloon_alt_rand;
		if (new_alt < 1200)
			new_alt = 1200;
		if (new_alt > 4500)
			new_alt = 4500;

		return {
			"lat": min_ahead_lat,
			"lon": spawn_lon,
			"alt": new_alt,
			"heading": 0,
			"lateral_deg": lateral_deg
		};
	};

	var applyBullseyeFacing = func(balloon_index, lat, lon) {
		var face_hdg = publishBalloonFacing(lat, lon);
		if (bullseyeArray[balloon_index] != nil)
		{
			var sign = bullseyeArray[balloon_index];
			if (sign.getNode("heading") != nil)
				sign.getNode("heading").setValue(face_hdg);
			if (sign.getNode("heading-deg") != nil)
				sign.getNode("heading-deg").setValue(face_hdg);
		}
	};

	var ensureBullseyeListener = func() {
		if (bullseyeListenerInstalled) return;
		bullseyeListenerInstalled = 1;
		setlistener("/ai/models/model-added", func(v) {
			var path = v.getValue();
			if (path == nil) return;
			var cs = getprop(path ~ "/callsign");
			if (cs == nil or cs == "") return;
			if (substr(cs, 0, 12) != "sivaks_bsign") return;
			var hdg = bullseyePending[cs];
			if (hdg == nil) return;
			setprop(path ~ "/orientation/true-heading-deg", hdg);
			setprop(path ~ "/orientation/pitch-deg", 0);
			setprop(path ~ "/orientation/roll-deg", 0);
			bullseyePending[cs] = nil;
		});
	};

	# Bullseye overlay (billboard in XML — always faces camera).
	var BSIGN_MODEL = "AI/Aircraft/balloon/ca_sivaks_bullseye_sign.xml";
	var BSIGN_ALT_OFFSET_FT = 12;
	var ADOT_MODEL = "AI/Aircraft/balloon/ca_sivaks_aim_dot.xml";
	# Hit slant-range (ft) matches required_hit_distance below.
	var HIT_RADIUS_BASE_FT = 180;
	var HIT_RADIUS_MIN_FT = 85;
	var HIT_RADIUS_PER_LEVEL_FT = 20;
	# Visual scale at level 0 (full hitbox); shrinks with level via /algorithm/game/*-visual-scale.
	var BULLSEYE_SCALE_AT_BASE_HIT = 3.2;
	var AIM_DOT_SCALE_RATIO = 0.42;
	var getHitRadiusFt = func(level) {
		var radius_ft = HIT_RADIUS_BASE_FT - (level * HIT_RADIUS_PER_LEVEL_FT);
		if (radius_ft < HIT_RADIUS_MIN_FT)
			radius_ft = HIT_RADIUS_MIN_FT;
		return radius_ft;
	};

	var publishMarkerScales = func(level) {
		var hit_radius_ft = getHitRadiusFt(level);
		var bullseye_scale =
			(hit_radius_ft / HIT_RADIUS_BASE_FT) * BULLSEYE_SCALE_AT_BASE_HIT;
		var aim_scale = bullseye_scale * AIM_DOT_SCALE_RATIO;
		setprop("/algorithm/game/bullseye-visual-scale", bullseye_scale);
		setprop("/algorithm/game/aim-dot-visual-scale", aim_scale);
		setprop("/algorithm/game/hit-radius-ft", hit_radius_ft);
	};

	var scoringMarkerPosition = func(balloon_lat, balloon_lon, balloon_alt_ft) {
		return signPositionTowardPilot(balloon_lat, balloon_lon, balloon_alt_ft);
	};
	# After a scored pass, ignore lat-trigger until this many sim seconds.
	var PASS_COOLDOWN_SEC = 3.0;
	# Slant range (ft) used to track closest approach for hit vs miss on the current balloon.
	var PASS_APPROACH_ARM_FT = 8000;
	# Small latitude margin so pass scoring does not flutter on the exact balloon latitude.
	var PASS_LAT_MARGIN_DEG = 0.00003;
	# First target only: extra lead so 350 kt spawn has room to reach 500 kt before pass 1.
	var BALLOON_INIT_AHEAD_LAT = 0.030;
	var BALLOON_INIT_AHEAD_STEP_LAT = 0.008;
	var BALLOON_AHEAD_BASE_FT = 1800;
	var BALLOON_AHEAD_PER_LEVEL_FT = 200;
	var MAX_LATERAL_VISIBLE_ANGLE = 28;

	var removeAiByCallsign = func(callsign) {
		if (callsign == nil or callsign == "")
			return 0;
		var root = props.globals.getNode("/ai/models");
		if (root == nil)
			return 0;
		foreach (var typ; ["static", "aircraft", "multiplayer"])
		{
			foreach (var m; root.getChildren(typ))
			{
				var cs = m.getNode("callsign");
				if (cs == nil or cs.getValue() != callsign)
					continue;
				var idn = m.getNode("id");
				if (idn != nil)
				{
					fgcommand(
						"remove-aiobject",
						props.Node.new({"id": idn.getValue()})
					);
				}
				return 1;
			}
		}
		return 0;
	};

	var purgeCorrTargetModels = func() {
		var root = props.globals.getNode("/ai/models");
		if (root == nil)
			return;
		var ids_to_remove = [];
		var types = ["static", "aircraft", "multiplayer", "wingman"];
		foreach (var typ; types)
		{
			foreach (var m; root.getChildren(typ))
			{
				var cs = m.getNode("callsign");
				var model = m.getNode("model");
				if (model == nil)
					model = m.getNode("model-path");
				var cs_v = (cs != nil) ? cs.getValue() : "";
				var model_v = (model != nil) ? model.getValue() : "";
				var is_ours = 0;
				if (cs_v != "" and (
					find(cs_v, "sivaks_bsign") >= 0 or
					find(cs_v, "ca_corr_") >= 0))
					is_ours = 1;
				if (!is_ours and model_v != "" and (
					find(model_v, "ca_sivaks_balloon") >= 0 or
					find(model_v, "ca_sivaks_bullseye") >= 0 or
					find(model_v, "ca_sivaks_aim_dot") >= 0))
					is_ours = 1;
				if (!is_ours)
					continue;
				var idn = m.getNode("id");
				if (idn != nil)
					append(ids_to_remove, idn.getValue());
			}
		}
		foreach (var rid; ids_to_remove)
		{
			fgcommand(
				"remove-aiobject",
				props.Node.new({"id": rid})
			);
		}
	};

	var createBalloon = func(balloon_model, positionLat, positionLon, elevation_ft, heading)
	{
		last_balloon_geo_coord = geo.Coord.new().set_latlon(positionLat, positionLon);
		last_balloon_geo_coord.set_alt(elevation_ft/globals.M2FT);
		publishBalloonFacing(positionLat, positionLon);
		var new_object = props.Node.new({
			"type": "static",
			"model": balloon_model,
			"callsign": "ca_corr_balloon_0",
			"latitude": positionLat,
			"longitude": positionLon,
			"altitude": elevation_ft,
			"heading": 0,
			"heading-deg": 0,
			"search-order": "DATA_ONLY"
		});
		fgcommand("add-aiobject", new_object);
		return new_object;
	};

	var createBullseyeSign = func(positionLat, positionLon, elevation_ft, cs)
	{
		ensureBullseyeListener();
		var marker = scoringMarkerPosition(positionLat, positionLon, elevation_ft);
		var face_hdg = publishBalloonFacing(positionLat, positionLon);
		bullseyePending[cs] = face_hdg;
		var sign = props.Node.new({
			"type": "static",
			"model": BSIGN_MODEL,
			"callsign": cs,
			"latitude": marker.lat,
			"longitude": marker.lon,
			"altitude": marker.alt,
			"heading": face_hdg,
			"heading-deg": face_hdg,
			"search-order": "DATA_ONLY"
		});
		fgcommand("add-aiobject", sign);
		return sign;
	};

	var createAimDot = func(marker_lat, marker_lon, marker_alt)
	{
		var dot = props.Node.new({
			"type": "static",
			"model": ADOT_MODEL,
			"callsign": "ca_corr_dot_0",
			"latitude": marker_lat,
			"longitude": marker_lon,
			"altitude": marker_alt,
			"heading": 0,
			"heading-deg": 0,
			"search-order": "DATA_ONLY"
		});
		fgcommand("add-aiobject", dot);
		return dot;
	};

	var destroyActiveTarget = func() {
		# Remove every CorrActions target (all bullseye serials, not only the latest callsign).
		purgeCorrTargetModels();
		balloonsArray[0] = nil;
		bullseyeArray[0] = nil;
		aimDotArray[0] = nil;
	};

	var spawnActiveTarget = func(balloon_lat, balloon_lon, balloon_alt_ft, level) {
		if (level == nil)
			level = 0;
		var i = 0;
		destroyActiveTarget();
		balloonsArray[i] = createBalloon(
			BMODEL,
			balloon_lat,
			balloon_lon,
			balloon_alt_ft,
			0
		);
		bullseyeCallsigns[i] = "sivaks_bsign_" ~ i ~ "_" ~ bullseyeSerial;
		bullseyeSerial += 1;
		bullseyeArray[i] = createBullseyeSign(
			balloon_lat,
			balloon_lon,
			balloon_alt_ft,
			bullseyeCallsigns[i]
		);
		var marker = scoringMarkerPosition(
			balloon_lat,
			balloon_lon,
			balloon_alt_ft
		);
		aimDotArray[i] = createAimDot(
			marker.lat,
			marker.lon,
			marker.alt
		);
		last_balloon_lat = balloon_lat;
		last_balloon_lon = balloon_lon;
		last_balloon_alt = balloon_alt_ft;
		publishMarkerScales(level);
		active_target_id += 1;
		last_pass_scored_id = -1;
		print(
			"SPAWN target id=",
			active_target_id,
			" lat=",
			balloon_lat,
			" lon=",
			balloon_lon,
			" alt=",
			balloon_alt_ft,
			" level=",
			level
		);
	};

	# =========================================================
	# STEP 3: balloons update timer
	# HIGHER INTENSITY VERSION
	# =========================================================

	var last_balloon_sign = -1;
	var balloons_counted_passed = 0;
	var balloons_counted_hit = 0;
	var MAX_BALLOONS = MAX_BALLOONS;

	# =========================================================
	# DIFFICULTY SYSTEM
	# =========================================================

	var hardness_lon = 0;

	var hardness_lon_update_balloons_count =
		BALLOON_per_level;

	var hardness_lon_max_levels = 8;

	# 0 = balloons stay fixed between spawns (no gust / drift / wave).
	var BALLOON_DRIFT_ENABLED = 0;

	# =========================================================
	# DYNAMIC MOVEMENT ARRAYS
	# =========================================================

	var balloonDriftDirs = [];
	var balloonVerticalDrift = [];
	var balloonWavePhase = [];
	var balloonWaveSpeed = [];

	setsize(balloonDriftDirs, balloon_count);
	setsize(balloonVerticalDrift, balloon_count);
	setsize(balloonWavePhase, balloon_count);
	setsize(balloonWaveSpeed, balloon_count);

	forindex (var i; balloonDriftDirs)
	{
		if (BALLOON_DRIFT_ENABLED)
		{
			balloonDriftDirs[i] = {
				lat: 0,
				lon: (rand()-0.5)
			};

			balloonVerticalDrift[i] =
				(rand()-0.5);

			balloonWavePhase[i] =
				rand()*6.28;

			balloonWaveSpeed[i] =
				0.03 + (rand()*0.05);
		}
		else
		{
			balloonDriftDirs[i] = { lat: 0, lon: 0 };
			balloonVerticalDrift[i] = 0;
			balloonWavePhase[i] = 0;
			balloonWaveSpeed[i] = 0;
		}
	}

	# STEP 2: initial target (after hardness_lon exists)
	var position = geo.aircraft_position();
	var elevation = geo.elevation(position.lat(), position.lon());
	init_shift_val = BALLOON_INIT_AHEAD_LAT;
	var base_balloon_altitude = 2000;

	purgeCorrTargetModels();

	last_balloon_lat = position.lat() + init_shift_val;
	last_balloon_lon = position.lon() + ((0.003) * (rand() - 0.5));
	last_balloon_alt = base_balloon_altitude;
	spawnActiveTarget(
		last_balloon_lat,
		last_balloon_lon,
		base_balloon_altitude,
		hardness_lon
	);
	print(
		"INIT: aircraft_Lat=",
		position.lat(),
		" aircraft_Lon=",
		position.lon(),
		" target_Lat=",
		last_balloon_lat,
		" target_Lon=",
		last_balloon_lon
	);

	# =========================================================
	# GAME STATE
	# =========================================================

	var dist_aicraft_to_balloon_ft = 10000000;
	var min_dist_ft = 10000000;
	var pass_cooldown_until = 0;
	var pass_committed = 0;
	var pass_south_armed = 0;

	var airspeed_kt = 0;
	var vert_speed_fpm = 0;

	var hit_miss_msg = "undefined";
	var hit_miss_number = 0;

	# =========================================================
	# SOUNDS
	# =========================================================

	var sound_HIT_NODE = props.Node.new({
		path : getprop("/sim/fg-root")~"/Sounds",
		file : "overspeed2.wav",
		volume : 1
	});

	var sound_MISS_NODE = props.Node.new({
		path : getprop("/sim/fg-root")~"/Sounds",
		file : "stall.wav",
		volume : 1
	});

	# =========================================================
	# UPDATE LOOP
	# =========================================================

	var updateBalloons = func()
	{
		var position = geo.aircraft_position();
		var sim_elapsed = getprop("/sim/time/elapsed-sec");
		if (sim_elapsed == nil)
			sim_elapsed = 0;

		forindex (var i; balloonsArray)
		{
			if (balloonsArray[i] == nil)
				continue;

			# =====================================================
			# CURRENT DIFFICULTY
			# =====================================================

			var difficulty =
				1 + (hardness_lon * 0.6);

			var current_lat =
				balloonsArray[i].getNode("latitude").getValue();
			var current_lon =
				balloonsArray[i].getNode("longitude").getValue();
			var current_alt =
				balloonsArray[i].getNode("altitude").getValue();

			if (BALLOON_DRIFT_ENABLED)
			{
				var drift_strength =
					0.000018 * difficulty;

				var vertical_strength =
					10 * difficulty;

				var gust_probability =
					0.015 +
					(hardness_lon * 0.005);

				if (rand() < gust_probability)
				{
					balloonDriftDirs[i].lon =
						(rand()-0.5) *
						5 *
						difficulty;

					balloonDriftDirs[i].lat =
						(rand()-0.5) *
						1.2 *
						difficulty;

					balloonVerticalDrift[i] =
						(rand()-0.5) *
						4;

					balloonWaveSpeed[i] =
						0.03 +
						(rand()*0.08*difficulty);

					print(
						"GUST balloon=",
						i,
						" level=",
						hardness_lon
					);
				}

				current_lat =
					current_lat +
					(
						balloonDriftDirs[i].lat *
						drift_strength
					);

				current_lon =
					current_lon +
					(
						balloonDriftDirs[i].lon *
						drift_strength
					);

				balloonWavePhase[i] =
					balloonWavePhase[i] +
					balloonWaveSpeed[i];

				current_lon =
					current_lon +
					(
						math.sin(balloonWavePhase[i]) *
						drift_strength *
						12 *
						difficulty
					);

				current_lat =
					current_lat +
					(
						math.cos(balloonWavePhase[i]*1.3) *
						drift_strength *
						6 *
						difficulty
					);

				current_alt =
					current_alt +
					(
						balloonVerticalDrift[i] *
						vertical_strength
					);

				current_alt =
					current_alt +
					(
						math.sin(balloonWavePhase[i]*0.7) *
						12 *
						difficulty
					);

				if (current_alt < 1200)
					current_alt = 1200;

				if (current_alt > 4500)
					current_alt = 4500;
			}

			# =====================================================
			# APPLY POSITION
			# =====================================================

			balloonsArray[i].getNode("latitude")
				.setValue(current_lat);
			balloonsArray[i].getNode("longitude")
				.setValue(current_lon);
			balloonsArray[i].getNode("altitude")
				.setValue(current_alt);

			applyBullseyeFacing(i, current_lat, current_lon);
			publishMarkerScales(hardness_lon);

			var marker = scoringMarkerPosition(
				current_lat,
				current_lon,
				current_alt
			);

			if (bullseyeArray[i] != nil)
			{
				bullseyeArray[i].getNode("latitude")
					.setValue(marker.lat);
				bullseyeArray[i].getNode("longitude")
					.setValue(marker.lon);
				bullseyeArray[i].getNode("altitude")
					.setValue(marker.alt);
			}

			if (aimDotArray[i] != nil)
			{
				aimDotArray[i].getNode("latitude").setValue(marker.lat);
				aimDotArray[i].getNode("longitude").setValue(marker.lon);
				aimDotArray[i].getNode("altitude").setValue(marker.alt);
			}

			var score_alt_ft = marker.alt;
			setprop("/algorithm/game/balloon-lat", marker.lat);
			setprop("/algorithm/game/balloon-lon", marker.lon);
			setprop("/algorithm/game/balloon-alt", score_alt_ft);

			# "Level" should represent the next required hit, not passes (misses shouldn't skip level 8).
			setprop("/algorithm/game/balloon-level", balloons_counted_hit + 1);

			# =====================================================
			# DISTANCE TO BALLOON
			# =====================================================

			var balloon_pos = geo.Coord.new();

			balloon_pos.set_latlon(
				current_lat,
				current_lon
			);

			balloon_pos.set_alt(
				score_alt_ft/globals.M2FT
			);

			dist_aicraft_to_balloon_ft =
				position.direct_distance_to(balloon_pos)
				* globals.M2FT;

			# =====================================================
			# TRACK MIN DISTANCE (no 1200 ft cap — jet passes often never got inside it, so min_dist stayed huge)
			# =====================================================

			if (dist_aicraft_to_balloon_ft < min_dist_ft)
			{
				airspeed_kt =
					getprop("/velocities/airspeed-kt");

				vert_speed_fpm =
					getprop("/instrumentation/vertical-speed-indicator/indicated-speed-fpm");

				min_dist_ft =
					dist_aicraft_to_balloon_ft;
			}

			# Commit gate: remember closest approach while still south of the balloon.
			if (pass_committed == 0 and min_dist_ft <= PASS_APPROACH_ARM_FT)
				pass_committed = 1;

			if (position.lat() < current_lat - PASS_LAT_MARGIN_DEG)
				pass_south_armed = 1;

			# One score per target: pass_south_armed resets only after spawn (not when south of lat).
			var passed_balloon =
				(pass_south_armed and
				position.lat() > current_lat + PASS_LAT_MARGIN_DEG);

			# =====================================================
			# PASSED BALLOON (south-to-north gate; far approach = miss)
			# =====================================================

			if (
				passed_balloon
				and sim_elapsed >= pass_cooldown_until
				and last_pass_scored_id != active_target_id
			)
			{
				last_pass_scored_id = active_target_id;

				balloons_counted_passed =
					balloons_counted_passed + 1;

				setprop(
					"/algorithm/game/balloons-count",
					balloons_counted_passed
				);

				# Difficulty for *this* pass only (level-up below was tightening hit on the same balloon)
				var hardness_for_hit = hardness_lon;

				# =================================================
				# LEVEL UP
				# =================================================

				if (
					math.mod(
						balloons_counted_passed,
						hardness_lon_update_balloons_count
					) == 0
					and
					hardness_lon < hardness_lon_max_levels
				)
				{
					hardness_lon =
						hardness_lon + 1;

					print(
						"LEVEL UP -> ",
						hardness_lon
					);

					setprop(
						"/sim/messages/copilot",
						(hardness_lon >= hardness_lon_max_levels)
							? "End of simulation"
							: ("LEVEL " ~ hardness_lon)
					);
				}

				# =================================================
				# HIT DETECTION — wider envelope for 500 kt; no VSI gate (gauge often swings thousands fpm in a pass)
				# =================================================

				var required_hit_distance = getHitRadiusFt(hardness_for_hit);

				var passed_through_balloon =
					(min_dist_ft <= required_hit_distance);

				var vs_now = getprop("/instrumentation/vertical-speed-indicator/indicated-speed-fpm");
				if (vs_now == nil)
					vs_now = vert_speed_fpm;

				if (passed_through_balloon)
				{
					hit_miss_msg = "hit";
					hit_miss_number = 1;
					balloons_counted_hit = balloons_counted_hit + 1;
					setprop("/algorithm/game/balloons-hit-count", balloons_counted_hit);

					fgcommand(
						"play-audio-sample",
						sound_HIT_NODE
					);
				}
				else
				{
					hit_miss_msg = "miss";
					hit_miss_number = -1;

					fgcommand(
						"play-audio-sample",
						sound_MISS_NODE
					);
				}

				setprop(
					"/algorithm/game/balloon-hit",
					hit_miss_number
				);
				# True slant range at closest approach (for log post-process; balloon-* lat/lon update to NEXT spawn same frame)
				setprop(
					"/algorithm/game/balloon-scoring-closest-ft",
					min_dist_ft
				);
				print("PASS scored: ", hit_miss_msg, " min_dist_ft=", min_dist_ft, " req=", required_hit_distance, " vs=", vs_now);

				pass_cooldown_until = sim_elapsed + PASS_COOLDOWN_SEC;

				# =================================================
				# END GAME
				# =================================================

				# End after the 8th scored pass (hit or miss).
				if (balloons_counted_passed >= MAX_BALLOONS)
				{
					setprop("/algorithm/game/finished", 1);

					BalloonTimer.stop();

					sivaksStopTargetEdge();

					destroyActiveTarget();
					purgeCorrTargetModels();

					setprop("/sim/rendering/redout/enabled", 0);
					setprop("/sim/rendering/redout/internal/redout", 0);

					settimer(func {
						setprop("/sim/rendering/redout/enabled", 0);
						setprop("/sim/rendering/redout/internal/redout", 0);
						fgcommand("exit");
					}, 0.2);

					return;
				}

				# =================================================
				# CREATE NEXT BALLOON (only after scored pass; always ahead of aircraft)
				# =================================================

				var next_spawn = computeNextBalloonPosition(hardness_lon);
				var new_ballon_lat = next_spawn.lat;
				var new_ballon_lon = next_spawn.lon;
				var new_ballon_alt = next_spawn.alt;
				var new_balloon_heading = next_spawn.heading;
				var target_feedback =
					(passed_through_balloon ? "TARGET HIT" : "TARGET MISS");
				setprop("/sim/messages/copilot", target_feedback);

				print(
					"NEXT spawn ahead of AC: ac_lat=",
					position.lat(),
					" balloon_lat=",
					new_ballon_lat,
					" ahead_ft~",
					BALLOON_AHEAD_BASE_FT + (hardness_lon * BALLOON_AHEAD_PER_LEVEL_FT)
				);

				# =================================================
				# ONE TARGET ONLY — remove old AI, spawn one new target ahead
				# =================================================

				spawnActiveTarget(
					new_ballon_lat,
					new_ballon_lon,
					new_ballon_alt,
					hardness_lon
				);
				# Require a fresh south→north crossing for the new target (stops sound spam while north).
				pass_south_armed = 0;

				# =================================================
				# NEW DRIFT PROFILE (skipped when BALLOON_DRIFT_ENABLED = 0)
				# =================================================

				if (BALLOON_DRIFT_ENABLED)
				{
					balloonDriftDirs[i] = {
						lat:
							(rand()-0.5)
							*
							1.2
							*
							difficulty,

						lon:
							(rand()-0.5)
							*
							5
							*
							difficulty
					};

					balloonVerticalDrift[i] =
						(rand()-0.5)
						*
						4;

					balloonWavePhase[i] =
						rand()*6.28;

					balloonWaveSpeed[i] =
						0.03 +
						(rand()*0.08*difficulty);

					last_balloon_sign =
						((rand()>0.5)?1:-1);
				}
				else
				{
					balloonDriftDirs[i] = { lat: 0, lon: 0 };
					balloonVerticalDrift[i] = 0;
					balloonWavePhase[i] = 0;
					balloonWaveSpeed[i] = 0;
				}

				min_dist_ft = 10000000;
				pass_committed = 0;
				pass_south_armed = 0;
			}
		}
	}

	# =========================================================
	# TIMER
	# =========================================================

	var BalloonTimer =
		maketimer(0.02, updateBalloons);

	sivaksStartTargetEdge();

	BalloonTimer.start();
